parameters.jsCode:
// Build booking link with pre-filled info
const lead = $('Normalize Lead Data').item.json;
const slots = $input.first().json;

// Construct a pre-filled Cal.com link
const calBase = process.env.CAL_BOOKING_URL || 'https://cal.com/bverse/15min';
const params = new URLSearchParams({
  name: lead.customer_name,
  email: lead.customer_email,
  notes: `Interest: ${lead.service_interest}. Timeline: ${lead.timeline}.`
});

const bookingLink = `${calBase}?${params.toString()}`;

// Get first available slot for display
const firstSlot = slots?.slots ? Object.values(slots.slots)[0]?.[0]?.time : null;
const slotDisplay = firstSlot ? new Date(firstSlot).toLocaleString('en-US', { weekday: 'long', month: 'long', day: 'numeric', hour: 'numeric', minute: '2-digit' }) : 'Choose a time that works for you';

return [{
  json: {
    ...lead,
    booking_link: bookingLink,
    first_available_slot: slotDisplay
  }
}];

